import{_ as t,o as a,c as n,a7 as r}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Covenants","description":"","frontmatter":{},"headers":[],"relativePath":"en/covenants/index.md","filePath":"en/covenants/index.md","lastUpdated":1775394001000}'),o={name:"en/covenants/index.md"};function s(i,e,d,l,h,c){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="covenants" tabindex="-1">Covenants <a class="header-anchor" href="#covenants" aria-label="Permalink to &quot;Covenants&quot;">​</a></h1><p><strong>Covenants</strong> (密契) are universal equipment in Morimens. Unlike Wheels of Destiny, Covenants can be equipped by any Awakener, making them flexible gear options for your entire roster.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td>Type</td><td>Universal equipment</td></tr><tr><td>Acquisition</td><td>Stages, events, crafting</td></tr><tr><td>Equip Limit</td><td>Varies by slot</td></tr><tr><td>Tradeable</td><td>No</td></tr></tbody></table><h2 id="how-covenants-work" tabindex="-1">How Covenants Work <a class="header-anchor" href="#how-covenants-work" aria-label="Permalink to &quot;How Covenants Work&quot;">​</a></h2><ul><li>Covenants provide <strong>stat bonuses</strong> and <strong>passive effects</strong> that are not tied to any specific Awakener.</li><li>Any Awakener can equip any Covenant, allowing you to redistribute gear freely.</li><li>Covenants are ideal for filling equipment slots when you lack a character-specific Wheel of Destiny.</li></ul><h2 id="obtaining-covenants" tabindex="-1">Obtaining Covenants <a class="header-anchor" href="#obtaining-covenants" aria-label="Permalink to &quot;Obtaining Covenants&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Notes</th></tr></thead><tbody><tr><td>Stage Drops</td><td>Farm from various stage types</td></tr><tr><td>Event Rewards</td><td>Limited-time event shops and milestones</td></tr><tr><td><a href="./../modes/smelting.html">Smelting Room</a></td><td>Craft Covenants using gathered materials</td></tr><tr><td>Investigation</td><td>Reward from <a href="./../modes/investigation.html">Investigation</a> runs</td></tr></tbody></table><h2 id="covenants-vs-wheels-of-destiny" tabindex="-1">Covenants vs. Wheels of Destiny <a class="header-anchor" href="#covenants-vs-wheels-of-destiny" aria-label="Permalink to &quot;Covenants vs. Wheels of Destiny&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Covenants</th><th>Wheels of Destiny</th></tr></thead><tbody><tr><td>Equip restriction</td><td>None (universal)</td><td>Character-specific</td></tr><tr><td>Source</td><td>Stages, events, crafting</td><td>Primarily gacha</td></tr><tr><td>Power level</td><td>General purpose</td><td>Higher (tailored passives)</td></tr><tr><td>Flexibility</td><td>Can swap between characters</td><td>Locked to one Awakener</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Covenants are the backbone of equipment for free-to-play players. Since they can be moved between Awakeners, a single strong Covenant set can gear up whichever character you need for the current content.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./list.html">Covenants List</a></li><li><a href="./../wheels/">Wheels of Destiny</a></li><li><a href="./../awakeners/">Awakener Overview</a></li></ul>',13)])])}const b=t(o,[["render",s]]);export{u as __pageData,b as default};
